+function generateOperationId(): string {
+  const chars = "abcdefghijklmnopqrstuvwxyz0123456789";
+  const randomBytes = new Uint8Array(12);
+  crypto.getRandomValues(randomBytes);
+  let result = "";
+  for (let i = 0; i < 12; i++) {
+    result += chars.charAt(randomBytes[i]! % chars.length);
+  }
+  return `gso_${result}`;
